import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Api from "../api/Api";

function Admin() {
  const [users, setUsers] = useState([]);

  const [showRequests, setShowRequests] = useState(false);
  const [requests, setRequests] = useState([]);

  const [orderMap, setOrderMap] = useState({});
  const [isSorted, setIsSorted] = useState(false);

  const fetchUsers = async () => {
    try {
      const res = await axios.get(Api.get_All_User);
      setUsers(res.data || []);
    } catch (err) {
      console.log(err);
    }
  };

  const fetchRequests = async () => {
    try {
      const res = await axios.get(Api.get_All_Emg_Req);
      const data = res.data?.data || res.data || [];
      setRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log(err);
      setRequests([]);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  // ================= ASSIGN ORDER (MAIN) =================
  const handleAssignOrder = async (id) => {
    try {
      const order = orderMap[id];

      if (!order && order !== 0) {
        return alert("Enter order first");
      }

      const res = await axios.put(
        `${Api.update_Schedule_Order}/${id}`,
        {
          scheduleOrder: Number(order),
        }
      );

      if (res.data?.success) {
        alert("Order Assigned Successfully");

        fetchRequests();
        setIsSorted(false);
      }

    } catch (err) {
      console.log(err);
    }
  };

  // ================= UPDATE ASSIGN (SECOND BUTTON) =================
  const handleUpdateAssign = async (id) => {
    try {
      const order = orderMap[id];

      if (!order && order !== 0) {
        return alert("Enter order to update");
      }

      const res = await axios.put(
        `${Api.update_Schedule_Order}/${id}`,
        {
          scheduleOrder: Number(order),
        }
      );

      if (res.data?.success) {
        alert("Order Updated Successfully");

        fetchRequests();
        setOrderMap({});
        setIsSorted(false);
      }

    } catch (err) {
      console.log(err);
    }
  };

  // ================= SORT =================
  const displayedRequests = isSorted
    ? [...requests].sort(
        (a, b) => (a.scheduleOrder || 0) - (b.scheduleOrder || 0)
      )
    : requests;

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-700 via-emerald-600 to-teal-700 flex items-center justify-center p-6">

      <div className="bg-white w-full max-w-6xl rounded-3xl shadow-2xl p-8">

        {/* HEADER */}
        <div className="text-center mb-10">
          <div className="text-7xl mb-3">🚛</div>
          <h1 className="text-4xl font-bold">Admin Dashboard</h1>
        </div>

        {/* ACTIONS */}
        <div className="flex justify-center gap-4 flex-wrap">

          <Link to="/send-otp">
            <button className="bg-green-600 text-white px-6 py-3 rounded-xl">
              ➕ Create User
            </button>
          </Link>

          <button
            onClick={() => {
              setShowRequests(!showRequests);
              fetchRequests();
            }}
            className="bg-blue-600 text-white px-6 py-3 rounded-xl"
          >
            👁 View Requests
          </button>

          <button
            onClick={() => setIsSorted(true)}
            className="bg-purple-600 text-white px-6 py-3 rounded-xl"
          >
            🔥 Final Sort
          </button>

        </div>

        {/* USERS */}
        <div className="mt-10">
          <h2 className="text-xl font-bold mb-3">Users</h2>

          {users.map((u) => (
            <div key={u._id} className="border p-2 mb-2">
              {u.name} - {u.mobile}
            </div>
          ))}
        </div>

        {/* REQUESTS */}
        {showRequests && (
          <div className="mt-10">

            <h2 className="text-2xl font-bold mb-4">
              Emergency Requests
            </h2>

            {displayedRequests.length === 0 ? (
              <p>No requests found</p>
            ) : (
              displayedRequests.map((req) => (
                <div
                  key={req._id}
                  className="border p-4 rounded-lg mb-3 bg-gray-50"
                >

                  <p>📍 {req.location?.location}</p>
                  <p>Status: {req.status}</p>

                  <p className="font-bold text-blue-600">
                    Order: {req.scheduleOrder || 0}
                  </p>

                  {/* INPUT */}
                  <div className="flex gap-3 mt-3">

                    <input
                      type="number"
                      placeholder="Set order"
                      className="border p-2 rounded w-40"
                      value={orderMap[req._id] ?? ""}
                      onChange={(e) =>
                        setOrderMap({
                          ...orderMap,
                          [req._id]: e.target.value,
                        })
                      }
                    />

                    {/* ================= BUTTON 1 ================= */}
                    <button
                      onClick={() => handleAssignOrder(req._id)}
                      className="bg-green-600 text-white px-3 py-2 rounded"
                    >
                      Assign
                    </button>

                    {/* ================= BUTTON 2 ================= */}
                    <button
                      onClick={() => handleUpdateAssign(req._id)}
                      className="bg-yellow-500 text-white px-3 py-2 rounded"
                    >
                      Update
                    </button>

                  </div>

                </div>
              ))
            )}

          </div>
        )}

      </div>
    </div>
  );
}

export default Admin;
